#[derive(Clone)]
struct LowerCtx {
    scopes: Vec<ScopeFrame>,
    flow: FlowState,
    next_local: LocalId,
    next_loan: LoanId,
    declared_result: Option<Ty>,
    return_boundary: Option<ReturnBoundary>,
    returned_types: Vec<Ty>,
    function_name: Option<String>,
    origin: ItemOrigin,
    type_substitutions: HashMap<String, Type>,
    loops: Vec<LoopFrame>,
    guard_move_restricted: HashSet<LocalId>,
    inspection_bindings: HashMap<LocalId, InspectionBinding>,
    borrowed_parameter_regions: HashMap<LocalId, (Option<String>, bool)>,
    reference_loans: HashMap<LocalId, Vec<LoanId>>,
    reference_value_depth: usize,
    unsafe_depth: usize,
    active_throws_error: Option<Ty>,
    active_custom_effects: HashSet<String>,
    active_custom_effect_sources: HashMap<String, Type>,
    lexical_handler_effects: HashSet<String>,
    lexical_handler_effect_sources: HashMap<String, Type>,
    recursive_frame_calls: HashMap<String, RecursiveFrameCall>,
    source_closures: HashMap<LocalId, Binding>,
}

impl LowerCtx {
    fn for_function(name: &str, result: Option<Ty>, origin: ItemOrigin) -> Self {
        Self {
            scopes: vec![ScopeFrame::new()],
            flow: FlowState::default(),
            next_local: 0,
            next_loan: 0,
            declared_result: result,
            return_boundary: None,
            returned_types: Vec::new(),
            function_name: Some(name.to_owned()),
            origin,
            type_substitutions: HashMap::new(),
            loops: Vec::new(),
            guard_move_restricted: HashSet::new(),
            inspection_bindings: HashMap::new(),
            borrowed_parameter_regions: HashMap::new(),
            reference_loans: HashMap::new(),
            reference_value_depth: 0,
            unsafe_depth: 0,
            active_throws_error: None,
            active_custom_effects: HashSet::new(),
            active_custom_effect_sources: HashMap::new(),
            lexical_handler_effects: HashSet::new(),
            lexical_handler_effect_sources: HashMap::new(),
            recursive_frame_calls: HashMap::new(),
            source_closures: HashMap::new(),
        }
    }

    fn for_global(origin: ItemOrigin) -> Self {
        Self {
            scopes: vec![ScopeFrame::new()],
            flow: FlowState::default(),
            next_local: 0,
            next_loan: 0,
            declared_result: None,
            return_boundary: None,
            returned_types: Vec::new(),
            function_name: None,
            origin,
            type_substitutions: HashMap::new(),
            loops: Vec::new(),
            guard_move_restricted: HashSet::new(),
            inspection_bindings: HashMap::new(),
            borrowed_parameter_regions: HashMap::new(),
            reference_loans: HashMap::new(),
            reference_value_depth: 0,
            unsafe_depth: 0,
            active_throws_error: None,
            active_custom_effects: HashSet::new(),
            active_custom_effect_sources: HashMap::new(),
            lexical_handler_effects: HashSet::new(),
            lexical_handler_effect_sources: HashMap::new(),
            recursive_frame_calls: HashMap::new(),
            source_closures: HashMap::new(),
        }
    }

    fn lookup(&self, name: &str) -> Option<&LocalInfo> {
        self.scopes
            .iter()
            .rev()
            .find_map(|scope| scope.names.get(name))
    }

    fn has_type_parameter(&self, name: &str) -> bool {
        self.type_substitutions.contains_key(name)
    }

    fn shadows_top_level_name(&self, name: &str) -> bool {
        self.lookup(name).is_some() || self.has_type_parameter(name)
    }

    fn fresh_local(&mut self) -> LocalId {
        let id = self.next_local;
        self.next_local += 1;
        id
    }

    fn push_scope(&mut self) {
        self.scopes.push(ScopeFrame::new());
    }

    fn pop_scope(&mut self) {
        let scope = self.scopes.pop().expect("cannot pop all scopes");
        for loan in scope.lexical_loans {
            self.flow.loans.remove(&loan);
        }
        for alternative in &mut self.flow.uninitialized {
            alternative.retain(|place| !scope.locals.contains(&place.local));
        }
        self.flow.normalize_uninitialized();
    }

    fn pop_scope_preserving_loans(&mut self, preserved: &[LoanId]) {
        let scope = self.scopes.pop().expect("cannot pop all scopes");
        for loan in scope.lexical_loans {
            if preserved.contains(&loan) {
                let parent = self
                    .scopes
                    .last_mut()
                    .expect("an escaping block reference has a parent scope");
                if !parent.lexical_loans.contains(&loan) {
                    parent.lexical_loans.push(loan);
                }
            } else {
                self.flow.loans.remove(&loan);
            }
        }
        for alternative in &mut self.flow.uninitialized {
            alternative.retain(|place| !scope.locals.contains(&place.local));
        }
        self.flow.normalize_uninitialized();
    }

    fn flow_without_current_scope(&self, mut flow: FlowState) -> FlowState {
        let scope = self.scopes.last().expect("at least one scope");
        for loan in &scope.lexical_loans {
            flow.loans.remove(loan);
        }
        for alternative in &mut flow.uninitialized {
            alternative.retain(|place| !scope.locals.contains(&place.local));
        }
        flow.normalize_uninitialized();
        flow
    }

    fn flow_without_scopes_from(&self, scope_depth: usize, mut flow: FlowState) -> FlowState {
        for scope in &self.scopes[scope_depth..] {
            for loan in &scope.lexical_loans {
                flow.loans.remove(loan);
            }
            for alternative in &mut flow.uninitialized {
                alternative.retain(|place| !scope.locals.contains(&place.local));
            }
        }
        flow.normalize_uninitialized();
        flow
    }

    fn outer_local_ids(&self) -> HashSet<LocalId> {
        self.scopes
            .iter()
            .flat_map(|scope| scope.locals.iter().copied())
            .collect()
    }

    fn insert_local(&mut self, name: String, local: LocalInfo) -> bool {
        let scope = self.scopes.last_mut().expect("at least one scope");
        if scope.names.contains_key(&name) {
            return false;
        }
        scope.locals.push(local.id);
        scope.names.insert(name, local);
        true
    }
}

