    #[test]
    fn rejects_unsupported_gats_and_associated_cycles() {
        let cases = [
            (
                r#"
	let Generic = trait {
	  let Item(T: type): type
	}
	let Node = struct(value: i32)
	extend Node: Generic {
	  let Item = i32
		}
		let main(): i32 = { 0 }
		"#,
                "must name a generic type constructor",
            ),
            (
                r#"
let Cycle = trait {
  let A: type
  let B: type
}
let Node = struct(value: i32)
extend Node: Cycle {
  let A = B
  let B = A
}
let main(): i32 = { 0 }
"#,
                "associated type cycle",
            ),
            (
                r#"
let Broken = trait {
  let read(borrow self)(): Missing
}
let main(): i32 = { 0 }
"#,
                "unknown type `Missing`",
            ),
            (
                r#"
let Conflict(T: type) = trait {
  let T: type
}
let main(): i32 = { 0 }
"#,
                "conflicts with a trait type parameter",
            ),
            (
                r#"
let Read = trait {
  let read(borrow self)(): i32
}
let Number = struct(value: i32)
extend Number: Read {
  let read(borrow value: Number)(): i32 = { value.value }
}
let main(): i32 = { 0 }
"#,
                "signature mismatch",
            ),
            (
                r#"
let Boxed = struct(value: i32)
let InvalidCopy = trait {
  let consume(borrow self)(copy value: Boxed): i32
}
let main(): i32 = { 0 }
"#,
                "requires `Copy`",
            ),
            (
                r#"
let Read = trait {
  let read(borrow self)(): i32
}
let Number = struct(value: i32)
extend Number: Read {}
extend Number: Read {
  let read(borrow self)(): i32 = { self.value }
}
let main(): i32 = { 0 }
"#,
                "duplicate trait implementation",
            ),
        ];
        for (source, expected) in cases {
            let diagnostics = compile_text(source).expect_err("trait source must be rejected");
            assert!(
                diagnostics
                    .iter()
                    .any(|diagnostic| diagnostic.message.contains(expected)),
                "missing `{expected}` in {diagnostics:?}"
            );
        }
    }

